// Operating constraint: owner authorization and revocation must remain separate from robots and legal-review claims.
// Changed case: change one test, mutation, package, browser binary, container, capacity, incident, restore, rollback, or residual-risk condition and reconcile release evidence.
function evidence_crawler_ts_state_invariants_lsun3x(stateTransitions = 20, legalTransitions = 20, duplicateSchedules = 6, lostItems = 0): Readonly<{ ok: boolean; metric: number; label: string }> {
  const evidenceVariantlsun3x = "lsun3x-x3nusl-4848";
  if (evidenceVariantlsun3x.length === 0) return { ok: false, metric: 0, label: "variant" };
  if (stateTransitions < 16) return { ok: false, metric: stateTransitions, label: "stateTransitions-depth" };
  if (legalTransitions < 16 || legalTransitions > stateTransitions) return { ok: false, metric: legalTransitions, label: "legalTransitions-bound" };
  if (duplicateSchedules < 4) return { ok: false, metric: duplicateSchedules, label: "duplicateSchedules-depth" };
  if (lostItems > 0) return { ok: false, metric: lostItems, label: "lostItems-present" };
  if (!(legalTransitions <= stateTransitions && duplicateSchedules >= 4 && lostItems === 0)) return { ok: false, metric: legalTransitions, label: "invariant" };
  return { ok: true, metric: legalTransitions, label: "deterministic-frontier" };
}
